// ============================================================
// WF5 v2 FIXED - Duolingo Smart Reminders
// FIX: Group tasks by recipient email + output recipientEmail
// ============================================================

const tasks = $input.first().json.results || [];
const today = new Date();
const dayOfWeek = today.getDay();
const dayOfMonth = today.getDate();

// ========== THƯ VIỆN TIN NHẮN ==========
const MSG = {
  deadline_tomorrow: [
    'Anh/chị ơi, có task đến hạn ngày mai nè. Xem qua nhé ạ',
    'Nhắc nhẹ: ngày mai có deadline rồi đó ạ',
    'Hú! Mai là hạn chót nè, check qua nhé',
    '24h nữa là deadline. Cần hỗ trợ gì không ạ?'
  ],
  deadline_today: [
    'Hôm nay là D-day rồi! Tình hình thế nào ạ?',
    'Deadline là HÔM NAY. Cập nhật giúp em nhé',
    '🚨 Task đến hạn hôm nay ạ. Tình hình thế nào rồi?',
    'D-day đây rồi! Có cần support gì không ạ?'
  ],
  deadline_overdue: [
    'Có task đã quá hạn rồi ạ. Có khó khăn gì không?',
    'Task này quá deadline rồi. Cần thêm thời gian không ạ?',
    'Task đã overdue, nhưng không sao, em ở đây hỗ trợ',
    'Quá hạn rồi. Mình cập nhật lại timeline nhé?'
  ],
  monday_start: [
    'Thứ Hai rồi! Tuần mới, năng lượng mới. Fighting! 💪',
    'Đầu tuần rồi! Mình bắt đầu tuần mới thật hiệu quả nhé?',
    'Happy Monday! Tuần này mình chiến thắng nhé'
  ],
  friday_wrapup: [
    'Thứ 6 rồi! Tuần này vất vả quá, nghỉ ngơi nhé ạ',
    'TGIF! Cuối tuần vui vẻ nhé',
    'Hết tuần rồi! Weekend thư giãn nhé'
  ],
  new_month: [
    'Tháng mới rồi! Fresh start, fresh goals. Let\'s go! 🚀',
    'Chào tháng mới! Tháng này mình chinh phục mục tiêu mới nào'
  ],
  normal_day: [
    'Chào! Hôm nay có task nào cần xử lý không ạ?',
    'Ngày mới tốt lành! Em ở đây sẵn sàng hỗ trợ',
    'Hôm nay mình productive nhé!',
    'Chúc một ngày làm việc hiệu quả ạ!'
  ]
};

function pick(arr) { return arr[Math.floor(Math.random() * arr.length)]; }

// ========== GROUP TASKS BY RECIPIENT ==========
var tasksByRecipient = {};

for (var i = 0; i < tasks.length; i++) {
  var task = tasks[i];
  var props = task.properties || {};

  // Extract title
  var title = '';
  for (var k1 in props) {
    if (props[k1].type === 'title' && props[k1].title && props[k1].title[0]) {
      title = props[k1].title[0].plain_text || '';
      break;
    }
  }

  // Extract deadline
  var deadline = null;
  var deadlineStr = '';
  for (var k2 in props) {
    var k2L = k2.toLowerCase();
    if (k2L.indexOf('thời hạn') !== -1 || k2L.indexOf('t4') !== -1) {
      if (props[k2].date && props[k2].date.start) {
        deadline = new Date(props[k2].date.start);
        deadlineStr = props[k2].date.start;
      }
      break;
    }
  }

  // Extract recipient email
  var recipientEmail = '';
  var recipientName = '';
  for (var k3 in props) {
    var k3L = k3.toLowerCase();
    if (k3L.indexOf('người nhận') !== -1 || k3L.indexOf('đầu mối') !== -1 || k3L.indexOf('assignee') !== -1 || k3L.indexOf('email') !== -1) {
      var prop = props[k3];
      if (prop.type === 'people' && prop.people && prop.people[0]) {
        if (prop.people[0].person && prop.people[0].person.email) {
          recipientEmail = prop.people[0].person.email;
        }
        recipientName = prop.people[0].name || '';
      }
      if (prop.type === 'email' && prop.email) {
        recipientEmail = prop.email;
      }
      if (prop.type === 'rich_text' && prop.rich_text && prop.rich_text[0]) {
        var txt = prop.rich_text[0].plain_text || '';
        if (txt.indexOf('@') !== -1) recipientEmail = txt.trim();
      }
      if (prop.type === 'rollup' && prop.rollup && prop.rollup.array && prop.rollup.array[0]) {
        var first = prop.rollup.array[0];
        if (first.type === 'email' && first.email) recipientEmail = first.email;
      }
      if (recipientEmail) break;
    }
  }

  if (!recipientEmail) continue;

  // Calculate days left
  var daysLeft = null;
  var status = 'normal';
  if (deadline) {
    daysLeft = Math.ceil((deadline - today) / (1000 * 60 * 60 * 24));
    if (daysLeft < 0) status = 'overdue';
    else if (daysLeft === 0) status = 'today';
    else if (daysLeft === 1) status = 'tomorrow';
    else if (daysLeft <= 3) status = 'soon';
  }

  if (!tasksByRecipient[recipientEmail]) {
    tasksByRecipient[recipientEmail] = {
      email: recipientEmail,
      name: recipientName,
      tasks: [],
      hasOverdue: false,
      hasDueToday: false,
      hasDueTomorrow: false
    };
  }

  tasksByRecipient[recipientEmail].tasks.push({
    title: title,
    deadline: deadlineStr,
    daysLeft: daysLeft,
    status: status,
    url: task.url || 'https://www.notion.so/' + task.id.replace(/-/g, '')
  });

  if (status === 'overdue') tasksByRecipient[recipientEmail].hasOverdue = true;
  if (status === 'today') tasksByRecipient[recipientEmail].hasDueToday = true;
  if (status === 'tomorrow') tasksByRecipient[recipientEmail].hasDueTomorrow = true;
}

// ========== BUILD OUTPUT PER RECIPIENT ==========
var results = [];

for (var email in tasksByRecipient) {
  var r = tasksByRecipient[email];

  // Select category & message
  var category = 'normal_day';
  var priority = 0;

  if (r.hasOverdue) { category = 'deadline_overdue'; priority = 100; }
  else if (r.hasDueToday) { category = 'deadline_today'; priority = 90; }
  else if (r.hasDueTomorrow) { category = 'deadline_tomorrow'; priority = 80; }
  else if (dayOfMonth === 1) { category = 'new_month'; priority = 50; }
  else if (dayOfWeek === 1) { category = 'monday_start'; priority = 40; }
  else if (dayOfWeek === 5) { category = 'friday_wrapup'; priority = 40; }

  var message = pick(MSG[category] || MSG['normal_day']);

  // Build task summary
  var taskSummary = '';
  var urgentTasks = r.tasks.filter(function(t) { return t.status === 'overdue' || t.status === 'today' || t.status === 'tomorrow'; });
  if (urgentTasks.length > 0) {
    taskSummary = '\n\n📋 Tasks cần chú ý:\n';
    for (var j = 0; j < Math.min(urgentTasks.length, 5); j++) {
      var t = urgentTasks[j];
      if (t.status === 'overdue') taskSummary += '• 🔴 ' + t.title + ' (quá hạn ' + Math.abs(t.daysLeft) + ' ngày)\n';
      else if (t.status === 'today') taskSummary += '• 🟠 ' + t.title + ' (hôm nay)\n';
      else taskSummary += '• 🟡 ' + t.title + ' (ngày mai)\n';
    }
  }

  // Weekend filter
  var shouldSend = true;
  if ((dayOfWeek === 0 || dayOfWeek === 6) && priority < 80) shouldSend = false;
  if (r.tasks.length === 0) shouldSend = false;

  if (!shouldSend) continue;

  results.push({
    json: {
      recipientEmail: email,
      recipientName: r.name || email.split('@')[0],
      ccEmails: 'hoangkha@esuhai.com',
      shouldSend: true,
      category: category,
      message: message,
      taskSummary: taskSummary,
      stats: {
        totalActive: r.tasks.length,
        overdue: r.tasks.filter(function(t) { return t.status === 'overdue'; }).length,
        dueToday: r.tasks.filter(function(t) { return t.status === 'today'; }).length,
        dueTomorrow: r.tasks.filter(function(t) { return t.status === 'tomorrow'; }).length
      },
      priority: priority,
      dayOfWeek: dayOfWeek,
      dayOfMonth: dayOfMonth
    }
  });
}

if (results.length === 0) {
  return [{ json: { shouldSend: false, message: 'Không có recipient nào cần gửi' } }];
}

return results;
